     1→/**
     2→ * Extract tools from OpenAPI document
     3→ * @returns {object} MCP config object
     4→ * @param openapi
     5→ */
     6→export function extractToolsFromOpenAPI(openapi) {
     7→  const mcpConfig = {
     8→    server: {
     9→      name: 'openapi-server',
    10→      securitySchemes: [],
    11→    },
    12→    tools: [],
    13→  };
    14→
    15→  // Process security schemes
    16→  if (openapi.components && openapi.components.securitySchemes) {
    17→    const securitySchemes = openapi.components.securitySchemes;
    18→    for (const name in securitySchemes) {
    19→      const scheme = securitySchemes[name];
    20→      mcpConfig.server.securitySchemes.push({
    21→        id: name,
    22→        type: scheme.type,
    23→        scheme: scheme.scheme,
    24→        in: scheme.in,
    25→        name: scheme.name,
    26→      });
    27→    }
    28→    // Sort security schemes by ID for consistent output
    29→    mcpConfig.server.securitySchemes.sort((a, b) => a.id.localeCompare(b.id));
    30→  }
    31→
    32→  // Process paths and operations
    33→  if (openapi.paths) {
    34→    for (const path in openapi.paths) {
    35→      const pathItem = openapi.paths[path];
    36→      const operations = getOperations(pathItem);
    37→      for (const method in operations) {
    38→        const operation = operations[method];
    39→        const tool = convertOperation(path, method, operation, openapi.servers);
    40→        // Create response template
    41→        tool.responseTemplate = createResponseTemplate(operation);
    42→        mcpConfig.tools.push(tool);
    43→      }
    44→    }
    45→  }
    46→  // Sort tools by name for consistent output
    47→  mcpConfig.tools.sort((a, b) => a.name.localeCompare(b.name));
    48→
    49→  return mcpConfig;
    50→}
    51→
    52→// 保持其余函数不变
    53→function getOperations(pathItem) {
    54→  const operations = {};
    55→
    56→  if (pathItem.get) operations.get = pathItem.get;
    57→  if (pathItem.post) operations.post = pathItem.post;
    58→  if (pathItem.put) operations.put = pathItem.put;
    59→  if (pathItem.delete) operations.delete = pathItem.delete;
    60→  if (pathItem.options) operations.options = pathItem.options;
    61→  if (pathItem.head) operations.head = pathItem.head;
    62→  if (pathItem.patch) operations.patch = pathItem.patch;
    63→  if (pathItem.trace) operations.trace = pathItem.trace;
    64→
    65→  return operations;
    66→}
    67→
    68→function convertOperation(path, method, operation, servers) {
    69→  // Generate a tool name
    70→  let toolName = operation.operationId || '';
    71→  if (!toolName) {
    72→    const pathName = path.replace(/[{}]/g, '').replace(/\//g, '_');
    73→    toolName = method.toLowerCase() + pathName.charAt(0).toUpperCase() + pathName.slice(1);
    74→  }
    75→
    76→  // Create the tool
    77→  const tool = {
    78→    name: toolName,
    79→    description: operation.summary || '',
    80→    args: [],
    81→    requestTemplate: createRequestTemplate(path, method, operation, servers),
    82→  };
    83→
    84→  // Convert parameters to arguments
    85→  // Process operation-level security requirements
    86→  if (operation.security && operation.security.length > 0) {
    87→    // Take the first security requirement
    88→    const securityRequirement = operation.security[0];
    89→    // Take the first scheme from that requirement
    90→    const schemeNames = Object.keys(securityRequirement);
    91→    if (schemeNames.length > 0) {
    92→      tool.requestTemplate.security = {
    93→        id: schemeNames[0],
    94→      };
    95→    }
    96→  }
    97→
    98→  // Convert parameters to arguments
    99→  if (operation.parameters) {
   100→    tool.args = operation.parameters.map(param => {
   101→      const arg = {
   102→        name: param.name,
   103→        description: param.description || '',
   104→        required: param.required || false,
   105→        position: param.in,
   106→      };
   107→
   108→      // Set the type based on the schema
   109→      if (param.schema) {
   110→        const schema = param.schema;
   111→        // Set the type based on the schema type
   112→        arg.type = schema.type;
   113→
   114→        // Handle enum values
   115→        if (schema.enum && schema.enum.length > 0) {
   116→          arg.enum = schema.enum;
   117→        }
   118→
   119→        // Handle array type
   120→        if (schema.type === 'array' && schema.items) {
   121→          arg.items = {
   122→            type: schema.items.type,
   123→          };
   124→        }
   125→
   126→        // Handle object type
   127→        if (schema.type === 'object' && schema.properties) {
   128→          arg.properties = {};
   129→          for (const propName in schema.properties) {
   130→            const prop = schema.properties[propName];
   131→            if (prop) {
   132→              arg.properties[propName] = {
   133→                type: prop.type,
   134→              };
   135→              if (prop.description) {
   136→                arg.properties[propName].description = prop.description;
   137→              }
   138→            }
   139→          }
   140→        }
   141→      }
   142→
   143→      return arg;
   144→    });
   145→  }
   146→
   147→  // Convert request body to arguments
   148→  if (operation.requestBody && operation.requestBody.content) {
   149→    for (const contentType in operation.requestBody.content) {
   150→      const mediaType = operation.requestBody.content[contentType];
   151→      if (mediaType.schema) {
   152→        const schema = mediaType.schema;
   153→
   154→        // For JSON and form content types, convert the schema to arguments
   155→        if (
   156→          contentType.includes('application/json') ||
   157→          contentType.includes('application/x-www-form-urlencoded')
   158→        ) {
   159→          // For object type, convert each property to an argument
   160→          if (schema.type === 'object' && schema.properties) {
   161→            for (const propName in schema.properties) {
   162→              const prop = schema.properties[propName];
   163→              if (!prop) {
   164→                continue;
   165→              }
   166→
   167→              const arg = {
   168→                name: propName,
   169→                description: prop.description || '',
   170→                type: prop.type,
   171→                required: schema.required && schema.required.includes(propName),
   172→                position: 'body',
   173→              };
   174→
   175→              // Handle enum values
   176→              if (prop.enum && prop.enum.length > 0) {
   177→                arg.enum = prop.enum;
   178→              }
   179→
   180→              // Handle array type
   181→              if (prop.type === 'array' && prop.items) {
   182→                arg.items = {
   183→                  type: prop.items.type,
   184→                  description: prop.items.description || '',
   185→                };
   186→
   187→                if (prop.items.minItems > 0) {
   188→                  arg.items.minItems = prop.items.minItems;
   189→                }
   190→
   191→                if (prop.items.type === 'object' && prop.items.properties) {
   192→                  arg.items.properties = prop.items.properties;
   193→                }
   194→              }
   195→
   196→              // Handle object type
   197→              if (prop.type === 'object' && prop.properties) {
   198→                arg.properties = {};
   199→                for (const subPropName in prop.properties) {
   200→                  const subProp = prop.properties[subPropName];
   201→                  if (subProp) {
   202→                    const subPropObj = {
   203→                      type: subProp.type,
   204→                      description: subProp.description || '',
   205→                    };
   206→
   207→                    if (subProp.default !== undefined) {
   208→                      subPropObj.default = subProp.default;
   209→                    }
   210→
   211→                    if (subProp.enum) {
   212→                      subPropObj.enum = subProp.enum;
   213→                    }
   214→
   215→                    arg.properties[subPropName] = subPropObj;
   216→                  }
   217→                }
   218→              }
   219→
   220→              // Handle allOf
   221→              if (!prop.type && prop.allOf && prop.allOf.length === 1) {
   222→                arg.type = 'object';
   223→                arg.properties = allOfHandle(prop.allOf[0]);
   224→              }
   225→
   226→              tool.args.push(arg);
   227→            }
   228→          }
   229→        }
   230→      }
   231→      break; // Only use the first content type
   232→    }
   233→  }
   234→
   235→  // Sort arguments by name for consistent output
   236→  tool.args.sort((a, b) => a.name.localeCompare(b.name));
   237→
   238→  return tool;
   239→}
   240→
   241→function allOfHandle(schema) {
   242→  const properties = {};
   243→
   244→  if (schema.type === 'object' && schema.properties) {
   245→    for (const propName in schema.properties) {
   246→      const prop = schema.properties[propName];
   247→      if (prop) {
   248→        properties[propName] = {
   249→          type: prop.type,
   250→        };
   251→
   252→        if (prop.description) {
   253→          properties[propName].description = prop.description;
   254→        }
   255→
   256→        // Handle nested allOf
   257→        if (!prop.type && prop.allOf && prop.allOf.length === 1) {
   258→          properties[propName].type = 'object';
   259→          properties[propName].properties = allOfHandle(prop.allOf[0]);
   260→        }
   261→      }
   262→    }
   263→  }
   264→
   265→  return properties;
   266→}
   267→
   268→function createRequestTemplate(path, method, operation, servers) {
   269→  let serverURL = servers && servers.length > 0 ? servers[0].url : '';
   270→  serverURL = serverURL.replace(/\/\//g, '/');
   271→
   272→  const template = {
   273→    url: serverURL + path,
   274→    method: method.toUpperCase(),
   275→    headers: [],
   276→  };
   277→
   278→  // Process operation-level security requirements
   279→  if (operation.security && operation.security.length > 0) {
   280→    for (const securityRequirement of operation.security) {
   281→      for (const schemeName in securityRequirement) {
   282→        template.security = { id: schemeName };
   283→        break;
   284→      }
   285→    }
   286→  }
   287→
   288→  // Add Content-Type header based on request body content type
   289→  if (operation.requestBody) {
   290→    for (const contentType in operation.requestBody.content) {
   291→      template.headers.push({
   292→        key: 'Content-Type',
   293→        value: contentType,
   294→      });
   295→      break; // Only use the first content type
   296→    }
   297→  }
   298→
   299→  return template;
   300→}
   301→
   302→/**
   303→ * Create a response template from an OpenAPI operation
   304→ * @param {object} operation OpenAPI operation object
   305→ * @returns {object} Response template object
   306→ */
   307→function createResponseTemplate(operation) {
   308→  // Find the success response (200, 201, etc.)
   309→  let successResponse = null;
   310→  if (operation.responses) {
   311→    for (const [code, responseRef] of Object.entries(operation.responses)) {
   312→      if (code.startsWith('2') && responseRef) {
   313→        successResponse = responseRef;
   314→        break;
   315→      }
   316→    }
   317→  }
   318→
   319→  // If there's no success response, don't add a response template
   320→  if (!successResponse || Object.keys(successResponse.content || {}).length === 0) {
   321→    return {};
   322→  }
   323→
   324→  // Create the response template
   325→  const template = {
   326→    prependBody:
   327→      '# API Response Information\n\n' +
   328→      "Below is the response from an API call. To help you understand the data, I've provided:\n\n" +
   329→      '1. A detailed description of all fields in the response structure\n' +
   330→      '2. The complete API response\n\n' +
   331→      '## Response Structure\n\n',
   332→  };
   333→
   334→  // Process each content type
   335→  for (const [contentType, mediaType] of Object.entries(successResponse.content)) {
   336→    if (!mediaType.schema) {
   337→      continue;
   338→    }
   339→
   340→    template.prependBody += `> Content-Type: ${contentType}\n\n`;
   341→    const schema = mediaType.schema;
   342→
   343→    // Generate field descriptions using recursive function
   344→    if (schema.type === 'array' && schema.items) {
