   161→    /**
   162→     * Get specified mcp server detail info. mcpServerId or namespaceId + mcpServerName is needed.
   163→     *
   164→     * @param namespaceId namespace id of mcp server
   165→     * @param mcpServerId id of mcp server
   166→     * @return detail info with {@link McpServerDetailInfo}
   167→     * @throws NacosException any exception during handling
   168→     */
   169→    public McpServerDetailInfo getMcpServerDetail(String namespaceId, String mcpServerId, String mcpServerName,
   170→            String version) throws NacosException {
   171→        mcpServerId = resolveMcpServerId(namespaceId, mcpServerName, mcpServerId);
   172→        
   173→        McpServerVersionInfo mcpServerVersionInfo = getMcpServerVersionInfo(namespaceId, mcpServerId);
   174→        if (StringUtils.isEmpty(version)) {
   175→            int size = mcpServerVersionInfo.getVersionDetails().size();
   176→            ServerVersionDetail last = mcpServerVersionInfo.getVersionDetails().get(size - 1);
   177→            version = last.getVersion();
   178→        }
   179→        
   180→        ConfigQueryChainRequest request = buildQueryMcpServerRequest(namespaceId, mcpServerId, version);
   181→        ConfigQueryChainResponse response = configQueryChainService.handle(request);
   182→        if (McpConfigUtils.isConfigNotFound(response.getStatus())) {
   183→            throw new NacosApiException(NacosApiException.NOT_FOUND, ErrorCode.MCP_SEVER_VERSION_NOT_FOUND,
   184→                    String.format("mcp server `%s` for version `%s` not found", mcpServerId, version));
   185→        }
   186→        
   187→        McpServerStorageInfo serverSpecification = JacksonUtils.toObj(response.getContent(),
   188→                McpServerStorageInfo.class);
   189→        
   190→        McpServerDetailInfo result = new McpServerDetailInfo();
   191→        result.setId(mcpServerId);
   192→        result.setNamespaceId(namespaceId);
   193→        BeanUtils.copyProperties(serverSpecification, result);
   194→        
   195→        List<ServerVersionDetail> versionDetails = mcpServerVersionInfo.getVersionDetails();
   196→        String latestVersion = mcpServerVersionInfo.getLatestPublishedVersion();
   197→        for (ServerVersionDetail versionDetail : versionDetails) {
   198→            versionDetail.setIs_latest(versionDetail.getVersion().equals(latestVersion));
   199→        }
   200→        result.setAllVersions(mcpServerVersionInfo.getVersionDetails());
   201→        
   202→        ServerVersionDetail versionDetail = result.getVersionDetail();
   203→        versionDetail.setIs_latest(versionDetail.getVersion().equals(latestVersion));
   204→        result.setVersion(versionDetail.getVersion());
   205→        
   206→        if (Objects.nonNull(serverSpecification.getToolsDescriptionRef())) {
   207→            McpToolSpecification toolSpec = toolOperationService.getMcpTool(namespaceId,
   208→                    serverSpecification.getToolsDescriptionRef());
   209→            result.setToolSpec(toolSpec);
   210→        }
   211→        
   212→        if (!AiConstants.Mcp.MCP_PROTOCOL_STDIO.equalsIgnoreCase(serverSpecification.getProtocol())) {
   213→            injectEndpoint(result);
   214→        }
   215→        return result;
   216→    }
