   236→    private void injectBackendEndpointRef(McpServerDetailInfo detailInfo) throws NacosException {
   237→        List<Instance> instances;
   238→        
   239→        instances = endpointOperationService.getMcpServerEndpointInstances(
   240→                detailInfo.getRemoteServerConfig().getServiceRef());
   241→        List<McpEndpointInfo> backendEndpoints = transferToMcpEndpointInfo(instances,
   242→                detailInfo.getRemoteServerConfig().getExportPath(), detailInfo.getProtocol());
   243→        detailInfo.setBackendEndpoints(backendEndpoints);
   244→    }
   245→    
   246→    private List<McpEndpointInfo> transferToMcpEndpointInfo(List<Instance> instances, String exportPath,
   247→            String protocol) {
   248→        List<McpEndpointInfo> endpointInfos = new LinkedList<>();
   249→        for (Instance each : instances) {
   250→            McpEndpointInfo mcpEndpointInfo = new McpEndpointInfo();
   251→            mcpEndpointInfo.setAddress(each.getIp());
   252→            mcpEndpointInfo.setPort(each.getPort());
   253→            if (Constants.PROTOCOL_TYPE_HTTP.equals(protocol)) {
   254→                exportPath = each.getMetadata().get(Constants.META_PATH);
   255→            }
   256→            mcpEndpointInfo.setPath(exportPath);
   257→            endpointInfos.add(mcpEndpointInfo);
   258→        }
   259→        return endpointInfos;
   260→    }
   261→    
   262→    private void injectFrontendEndpointRef(McpServerDetailInfo detailInfo) throws NacosException {
   263→        List<FrontEndpointConfig> frontEndpointConfigs = detailInfo.getRemoteServerConfig()
   264→                .getFrontEndpointConfigList();
   265→        if (CollectionUtils.isEmpty(frontEndpointConfigs)) {
   266→            detailInfo.setFrontendEndpoints(Collections.emptyList());
   267→            return;
   268→        }
   269→        List<McpEndpointInfo> frontendEndpoints = new LinkedList<>();
   270→        for (FrontEndpointConfig each : frontEndpointConfigs) {
   271→            if (AiConstants.Mcp.MCP_ENDPOINT_TYPE_REF.equals(each.getEndpointType())) {
   272→                McpServiceRef mcpServiceRef = McpRequestUtil.transferToMcpServiceRef(each.getEndpointData());
   273→                List<Instance> instances = endpointOperationService.getMcpServerEndpointInstances(mcpServiceRef);
   274→                List<McpEndpointInfo> endpointInfos = transferToMcpEndpointInfo(instances, each.getPath(),
   275→                        each.getType());
   276→                frontendEndpoints.addAll(endpointInfos);
   277→            } else if (AiConstants.Mcp.MCP_ENDPOINT_TYPE_DIRECT.equals(each.getEndpointType())) {
   278→                String address = each.getEndpointData().toString();
   279→                McpEndpointInfo endpointInfo = new McpEndpointInfo();
   280→                endpointInfo.setPath(each.getPath());
   281→                if (InternetAddressUtil.containsPort(address)) {
   282→                    String[] info = InternetAddressUtil.splitIpPortStr(address);
   283→                    endpointInfo.setAddress(info[0]);
   284→                    endpointInfo.setPort(Integer.parseInt(info[1]));
   285→                } else {
   286→                    endpointInfo.setAddress(address);
   287→                    endpointInfo.setPort(Constants.PROTOCOL_TYPE_HTTP.equals(each.getProtocol()) ? 80 : 443);
   288→                }
   289→                frontendEndpoints.add(endpointInfo);
   290→            } else {
   291→                frontendEndpoints.addAll(detailInfo.getBackendEndpoints());
   292→            }
   293→            detailInfo.setFrontendEndpoints(frontendEndpoints);
   294→        }
   295→    }
