   297→    /**
   298→     * Create new mcp server.
   299→     *
   300→     * @param namespaceId           namespace id of mcp server
   301→     * @param serverSpecification   mcp server specification, see {@link McpServerBasicInfo}
   302→     * @param toolSpecification     mcp server included tools, see {@link McpToolSpecification}, optional
   303→     * @param endpointSpecification mcp server endpoint specification, see {@link McpEndpointSpec}, optional
   304→     * @throws NacosException any exception during handling
   305→     */
   306→    public String createMcpServer(String namespaceId, McpServerBasicInfo serverSpecification,
   307→            McpToolSpecification toolSpecification, McpEndpointSpec endpointSpecification) throws NacosException {
   308→        
   309→        String existId = resolveMcpServerId(namespaceId, serverSpecification.getName(), StringUtils.EMPTY);
   310→        if (StringUtils.isNotEmpty(existId)) {
   311→            throw new NacosApiException(NacosApiException.CONFLICT, ErrorCode.RESOURCE_CONFLICT,
   312→                    String.format("mcp server `%s` has existed, please update it rather than create.",
   313→                            serverSpecification.getName()));
   314→        }
   315→        
   316→        ServerVersionDetail versionDetail = serverSpecification.getVersionDetail();
   317→        if (null == versionDetail && StringUtils.isNotBlank(serverSpecification.getVersion())) {
   318→            versionDetail = new ServerVersionDetail();
   319→            versionDetail.setVersion(serverSpecification.getVersion());
   320→            serverSpecification.setVersionDetail(versionDetail);
   321→        }
   322→        if (Objects.isNull(versionDetail) || StringUtils.isEmpty(versionDetail.getVersion())) {
   323→            throw new NacosApiException(NacosApiException.INVALID_PARAM, ErrorCode.PARAMETER_VALIDATE_ERROR,
   324→                    "Version must be specified in parameter `serverSpecification`");
   325→        }
   326→        String id;
   327→        String customMcpId = serverSpecification.getId();
   328→        
   329→        if (StringUtils.isEmpty(customMcpId)) {
   330→            id = UUID.randomUUID().toString();
   331→        } else {
   332→            if (!StringUtils.isUuidString(customMcpId)) {
   333→                throw new NacosApiException(NacosApiException.INVALID_PARAM, ErrorCode.PARAMETER_VALIDATE_ERROR,
   334→                        "parameter `serverSpecification.id` is not match uuid pattern,  must obey uuid pattern");
   335→            }
   336→            if (mcpServerIndex.getMcpServerById(serverSpecification.getId()) != null) {
   337→                throw new NacosApiException(NacosApiException.INVALID_PARAM, ErrorCode.PARAMETER_VALIDATE_ERROR,
   338→                        "parameter `serverSpecification.id` conflict with exist mcp server id");
   339→            }
   340→            
   341→            id = customMcpId;
   342→        }
   343→        
   344→        serverSpecification.setId(id);
   345→        ZonedDateTime currentTime = ZonedDateTime.now(ZoneOffset.UTC);
   346→        DateTimeFormatter formatter = DateTimeFormatter.ofPattern(Constants.RELEASE_DATE_FORMAT);
   347→        String formattedCurrentTime = currentTime.format(formatter);
   348→        versionDetail.setRelease_date(formattedCurrentTime);
   349→        
   350→        McpServerStorageInfo newSpecification = new McpServerStorageInfo();
   351→        BeanUtils.copyProperties(serverSpecification, newSpecification);
   352→        injectToolAndEndpoint(namespaceId, serverSpecification.getId(), newSpecification, toolSpecification,
   353→                endpointSpecification);
   354→        
   355→        McpServerVersionInfo versionInfo = buildServerVersionInfo(newSpecification, id, versionDetail);
   356→        
   357→        ConfigRequestInfo configRequestInfo = new ConfigRequestInfo();
   358→        configRequestInfo.setUpdateForExist(Boolean.FALSE);
   359→        
   360→        ConfigFormV3 mcpServerVersionForm = buildMcpServerVersionForm(namespaceId, versionInfo);
   361→        configOperationService.publishConfig(mcpServerVersionForm, configRequestInfo, null);
   362→        
   363→        ConfigForm configForm = buildMcpConfigForm(namespaceId, id, versionDetail.getVersion(), newSpecification);
   364→        configOperationService.publishConfig(configForm, configRequestInfo, null);
   365→        
   366→        // Delete the relevant cache after a successful database operation
   367→        invalidateCacheAfterDbOperation(namespaceId, serverSpecification.getName(), id);
   368→        
   369→        return id;
   370→    }
