   372→    private static McpServerVersionInfo buildServerVersionInfo(McpServerBasicInfo serverSpecification, String id,
   373→            ServerVersionDetail versionDetail) {
   374→        McpServerVersionInfo versionInfo = new McpServerVersionInfo();
   375→        versionInfo.setName(serverSpecification.getName());
   376→        versionInfo.setId(id);
   377→        versionInfo.setDescription(serverSpecification.getDescription());
   378→        versionInfo.setRepository(serverSpecification.getRepository());
   379→        versionInfo.setFrontProtocol(serverSpecification.getFrontProtocol());
   380→        versionInfo.setProtocol(serverSpecification.getProtocol());
   381→        versionInfo.setCapabilities(serverSpecification.getCapabilities());
