   387→    /**
   388→     * Update existed mcp server.
   389→     *
   390→     * <p>
   391→     * `namespaceId` and `mcpServerId` can't be changed.
   392→     * </p>
   393→     *
   394→     * @param namespaceId           namespace id of mcp server, used to mark which mcp server to update
   395→     * @param serverSpecification   mcp server specification, see {@link McpServerBasicInfo}
   396→     * @param toolSpecification     mcp server included tools, see {@link McpToolSpecification}, optional
   397→     * @param endpointSpecification mcp server endpoint specification, see {@link McpEndpointSpec}, optional
   398→     * @throws NacosException any exception during handling
   399→     */
   400→    public void updateMcpServer(String namespaceId, boolean isPublish, McpServerBasicInfo serverSpecification,
   401→            McpToolSpecification toolSpecification, McpEndpointSpec endpointSpecification) throws NacosException {
   402→        
   403→        String mcpServerId = serverSpecification.getId();
   404→        mcpServerId = resolveMcpServerId(namespaceId, serverSpecification.getName(), mcpServerId);
   405→        if (StringUtils.isEmpty(serverSpecification.getId())) {
   406→            serverSpecification.setId(mcpServerId);
   407→        }
   408→        
   409→        ServerVersionDetail versionDetail = serverSpecification.getVersionDetail();
   410→        if (null == versionDetail && StringUtils.isNotBlank(serverSpecification.getVersion())) {
   411→            versionDetail = new ServerVersionDetail();
   412→            versionDetail.setVersion(serverSpecification.getVersion());
   413→            serverSpecification.setVersionDetail(versionDetail);
   414→        }
   415→        if (Objects.isNull(versionDetail) || StringUtils.isEmpty(versionDetail.getVersion())) {
   416→            throw new NacosApiException(NacosApiException.INVALID_PARAM, ErrorCode.PARAMETER_VALIDATE_ERROR,
   417→                    "Version must be specified in parameter `serverSpecification`");
   418→        }
   419→        final McpServerVersionInfo mcpServerVersionInfo = getMcpServerVersionInfo(namespaceId, mcpServerId);
   420→        
   421→        String updateVersion = versionDetail.getVersion();
   422→        McpServerStorageInfo newSpecification = new McpServerStorageInfo();
   423→        BeanUtils.copyProperties(serverSpecification, newSpecification);
   424→        injectToolAndEndpoint(namespaceId, mcpServerId, newSpecification, toolSpecification, endpointSpecification);
   425→        
   426→        ConfigForm configForm = buildMcpConfigForm(namespaceId, mcpServerId, updateVersion, newSpecification);
   427→        configOperationService.publishConfig(configForm, new ConfigRequestInfo(), null);
   428→        
   429→        List<ServerVersionDetail> versionDetails = mcpServerVersionInfo.getVersionDetails();
   430→        Set<String> versionSet = versionDetails.stream().map(ServerVersionDetail::getVersion)
   431→                .collect(Collectors.toSet());
   432→        if (!versionSet.contains(updateVersion)) {
   433→            ServerVersionDetail version = new ServerVersionDetail();
   434→            version.setVersion(updateVersion);
   435→            versionDetails.add(version);
   436→            mcpServerVersionInfo.setVersions(versionDetails);
   437→        }
   438→        
   439→        if (isPublish) {
   440→            mcpServerVersionInfo.setName(newSpecification.getName());
   441→            mcpServerVersionInfo.setDescription(newSpecification.getDescription());
   442→            mcpServerVersionInfo.setRepository(newSpecification.getRepository());
   443→            mcpServerVersionInfo.setProtocol(newSpecification.getProtocol());
   444→            mcpServerVersionInfo.setFrontProtocol(newSpecification.getFrontProtocol());
   445→            mcpServerVersionInfo.setCapabilities(newSpecification.getCapabilities());
   446→            mcpServerVersionInfo.setLatestPublishedVersion(updateVersion);
   447→            
   448→            for (ServerVersionDetail detail : versionDetails) {
   449→                if (detail.getVersion().equals(updateVersion)) {
   450→                    ZonedDateTime currentTime = ZonedDateTime.now(ZoneOffset.UTC);
   451→                    DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd'T'HH:mm:ss'Z'");
   452→                    String formattedCurrentTime = currentTime.format(formatter);
   453→                    detail.setRelease_date(formattedCurrentTime);
   454→                    detail.setIs_latest(true);
   455→                    break;
   456→                } else {
   457→                    detail.setIs_latest(false);
   458→                }
   459→            }
   460→            mcpServerVersionInfo.setVersions(versionDetails);
   461→        }
   462→        
   463→        ConfigFormV3 mcpServerVersionForm = buildMcpServerVersionForm(namespaceId, mcpServerVersionInfo);
   464→        configOperationService.publishConfig(mcpServerVersionForm, new ConfigRequestInfo(), null);
   465→        
   466→        // Delete the relevant cache after a successful database operation
   467→        invalidateCacheAfterDbUpdateOperation(namespaceId, mcpServerVersionInfo.getName(),
   468→                serverSpecification.getName(), mcpServerId);
   469→    }
