   471→    /**
   472→     * Delete existed mcp server.
   473→     *
   474→     * @param namespaceId namespace id of mcp server
   475→     * @param mcpServerId name of mcp server
   476→     * @throws NacosException any exception during handling
   477→     */
   478→    public void deleteMcpServer(String namespaceId, String mcpName, String mcpServerId, String version)
   479→            throws NacosException {
   480→        mcpServerId = resolveMcpServerId(namespaceId, mcpName, mcpServerId);
   481→        McpServerVersionInfo mcpServerVersionInfo = getMcpServerVersionInfo(namespaceId, mcpServerId);
   482→        List<String> versionsNeedDelete = new ArrayList<>();
   483→        if (StringUtils.isNotEmpty(version)) {
   484→            versionsNeedDelete.add(version);
   485→        } else {
   486→            versionsNeedDelete = mcpServerVersionInfo.getVersionDetails().stream().map(ServerVersionDetail::getVersion)
   487→                    .collect(Collectors.toList());
   488→        }
   489→        
   490→        for (String versionNeedDelete : versionsNeedDelete) {
   491→            toolOperationService.deleteMcpTool(namespaceId, mcpServerId, versionNeedDelete);
   492→            endpointOperationService.deleteMcpServerEndpointService(namespaceId, mcpServerVersionInfo.getName());
   493→            String serverSpecDataId = McpConfigUtils.formatServerSpecInfoDataId(mcpServerId, versionNeedDelete);
   494→            configOperationService.deleteConfig(serverSpecDataId, Constants.MCP_SERVER_GROUP, namespaceId, null, null,
   495→                    "nacos", null);
   496→            String serverVersionDataId = McpConfigUtils.formatServerVersionInfoDataId(mcpServerId);
   497→            configOperationService.deleteConfig(serverVersionDataId, Constants.MCP_SERVER_VERSIONS_GROUP, namespaceId,
   498→                    null, null, "nacos", null);
   499→        }
   500→        
   501→        // Delete the relevant cache after a successful database operation
   502→        invalidateCacheAfterDbOperation(namespaceId, mcpName, mcpServerId);
   503→    }
