   505→    private void injectToolAndEndpoint(String namespaceId, String mcpServerId, McpServerStorageInfo serverSpecification,
   506→            McpToolSpecification toolSpecification, McpEndpointSpec endpointSpecification) throws NacosException {
   507→        serverSpecification.setCapabilities(new LinkedList<>());
   508→        if (null != toolSpecification && null != toolSpecification.getTools() && !toolSpecification.getTools()
   509→                .isEmpty()) {
   510→            toolOperationService.refreshMcpTool(namespaceId, serverSpecification, toolSpecification);
   511→            serverSpecification.getCapabilities().add(McpCapability.TOOL);
   512→            String version = serverSpecification.getVersionDetail().getVersion();
   513→            String toolSpecDataId = McpConfigUtils.formatServerToolSpecDataId(mcpServerId, version);
   514→            serverSpecification.setToolsDescriptionRef(toolSpecDataId);
   515→        }
   516→        if (null != endpointSpecification) {
   517→            Service service = endpointOperationService.createMcpServerEndpointServiceIfNecessary(namespaceId,
   518→                    serverSpecification.getName(), endpointSpecification);
   519→            McpServiceRef serviceRef = new McpServiceRef();
   520→            serviceRef.setNamespaceId(service.getNamespace());
   521→            serviceRef.setGroupName(service.getGroup());
   522→            serviceRef.setServiceName(service.getName());
   523→            serverSpecification.getRemoteServerConfig().setServiceRef(serviceRef);
   524→        }
   525→    }
