   610→    private void invalidateCacheAfterDbUpdateOperation(String namespaceId, String oldMcpName, String newMcpName,
   611→            String mcpServerId) {
   612→        try {
   613→            if (StringUtils.isNotEmpty(oldMcpName) && !oldMcpName.equals(newMcpName)) {
   614→                mcpServerIndex.removeMcpServerByName(namespaceId, oldMcpName);
   615→            }
   616→            if (StringUtils.isNotEmpty(newMcpName)) {
   617→                mcpServerIndex.removeMcpServerByName(namespaceId, newMcpName);
   618→            }
   619→            if (StringUtils.isNotEmpty(mcpServerId)) {
   620→                mcpServerIndex.removeMcpServerById(mcpServerId);
   621→            }
   622→            LOGGER.debug("Cache invalidated after updateMcpServer: namespaceId={}, oldName={}, newName={}, id={}",
   623→                    namespaceId, oldMcpName, newMcpName, mcpServerId);
   624→        } catch (Exception e) {
